import React, { useState } from "react";
import axios from "axios";

function App() {
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [file, setFile] = useState(null);
  const [msg, setMsg] = useState("");
  const [results, setResults] = useState([]);

  // Add Job
  const addJob = async () => {
    try {
      await axios.post("http://127.0.0.1:8000/job", {
        title: title,
        description: description
      });

      setMsg("Job Added Successfully");
    } catch (error) {
      console.log(error);
      setMsg("Error adding job");
    }
  };

  // Upload Resume
  const uploadResume = async () => {
    if (!file) {
      setMsg("Please select a file");
      return;
    }

    const formData = new FormData();
    formData.append("file", file);

    try {
      await axios.post(
        "http://127.0.0.1:8000/upload_resume",
        formData
      );

      setMsg("Resume Uploaded Successfully");
    } catch (error) {
      console.log(error);
      setMsg("Upload Failed");
    }
  };

  // Get Match Results
  const getMatches = async () => {
    try {
      const res = await axios.get("http://127.0.0.1:8000/match/1");

      if (res.data.rankings) {
        setResults(res.data.rankings);
      } else {
        setResults(res.data);
      }

      setMsg("Matching Complete");
    } catch (error) {
      console.log(error);
      setMsg("Matching Failed");
    }
  };

  return (
    <div
      style={{
        padding: "40px",
        background: "#0f172a",
        color: "white",
        minHeight: "100vh",
        fontFamily: "Arial"
      }}
    >
      <h1>ResumeX AI</h1>
      <p>Smart Resume Screening & Job Matching System</p>

      {/* Add Job Section */}
      <h2>Add Job</h2>

      <input
        type="text"
        placeholder="Job Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        style={input}
      />

      <br />
      <br />

      <textarea
        placeholder="Job Description"
        value={description}
        onChange={(e) => setDescription(e.target.value)}
        style={{ ...input, height: "100px" }}
      />

      <br />
      <br />

      <button style={btn} onClick={addJob}>
        Add Job
      </button>

      <hr style={{ margin: "30px 0" }} />

      {/* Upload Resume Section */}
      <h2>Upload Resume</h2>

      <input
        type="file"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <br />
      <br />

      <button style={btn} onClick={uploadResume}>
        Upload Resume
      </button>

      <br />
      <br />

      {/* Match Results */}
      <button style={btn} onClick={getMatches}>
        View AI Match Results
      </button>

      <div style={{ marginTop: "20px" }}>
        {results.map((item, index) => (
          <p key={index}>
            {item.resume || item.name} - {item.score}%
          </p>
        ))}
      </div>

      {/* Status Message */}
      <p style={{ marginTop: "20px", color: "#38bdf8" }}>{msg}</p>
    </div>
  );
}

const input = {
  padding: "10px",
  width: "320px",
  borderRadius: "8px",
  border: "none"
};

const btn = {
  padding: "12px 20px",
  border: "none",
  borderRadius: "8px",
  cursor: "pointer",
  marginRight: "10px"
};

export default App;
